// Aggregate into COO weekly-review context.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};

const leadsW   = allOf('Leads This Week');
const leadsP3  = allOf('Leads Prior 3w');
const bookings = allOf('Bookings This Week');
const quotes   = allOf('Quotes This Week');
const outreach = allOf('Outreach This Week');
const overdue  = allOf('Overdue Leads');
const clients  = allOf('Active Clients');

// Pipeline this week — count by status
const byStatus = {};
leadsW.forEach(function (l) {
  const s = (l && l.lead_status) || 'unknown';
  byStatus[s] = (byStatus[s] || 0) + 1;
});

// Sources this week
const bySource = {};
leadsW.forEach(function (l) {
  const s = (l && l.source) || 'unknown';
  bySource[s] = (bySource[s] || 0) + 1;
});

// Industry mix this week
const byIndustry = {};
leadsW.forEach(function (l) {
  const i = (l && l.industry) || 'unknown';
  byIndustry[i] = (byIndustry[i] || 0) + 1;
});

// Last week vs the prior 3 weeks (weekly average) — trend signal
const priorAvgPerWeek = Math.round(leadsP3.length / 3);
const leadsTrendPct = priorAvgPerWeek > 0 ? Math.round(((leadsW.length - priorAvgPerWeek) / priorAvgPerWeek) * 100) : null;

// Quote revenue if any
let totalQuotedCents = 0;
let acceptedQuotedCents = 0;
let declinedCount = 0;
let pendingCount = 0;
quotes.forEach(function (q) {
  if (!q) return;
  totalQuotedCents += Number(q.total_cents || 0);
  if (q.accepted_at) acceptedQuotedCents += Number(q.total_cents || 0);
  else if (q.declined_at) declinedCount++;
  else pendingCount++;
});
const acceptanceRatePct = quotes.length > 0 ? Math.round((quotes.length - declinedCount - pendingCount) / quotes.length * 100) : null;

// Outreach volume by channel
const outreachByChannel = {};
let outreachFailures = 0;
outreach.forEach(function (o) {
  if (!o) return;
  const c = (o.channel || 'other').toLowerCase();
  outreachByChannel[c] = (outreachByChannel[c] || 0) + 1;
  const s = (o.status || '').toLowerCase();
  if (s === 'failed' || s === 'undelivered' || s === 'bounced') outreachFailures++;
});

// MRR from active clients (paying ones)
const PLAN_PRICES = { founding_1997: 1997, standard_2497: 2497, construction_1497: 1497, moving_997: 997, cleaning_997: 997, salon_997: 997, intelligence_3997: 3997 };
let mrrCents = 0;
clients.forEach(function (c) {
  if (!c) return;
  if (c.subscription_status === 'active' || c.subscription_status === 'trialing') {
    mrrCents += (PLAN_PRICES[c.subscription_plan] || (c.monthly_retainer || 0)) * 100;
  }
});

// Bookings this week
const bookingsByChannel = {};
bookings.forEach(function (b) {
  if (!b) return;
  const c = (b.channel || 'other').toLowerCase();
  bookingsByChannel[c] = (bookingsByChannel[c] || 0) + 1;
});

// Overdue
const overdueHighScore = overdue.filter(function (l) { return (l.lead_score || 0) >= 60; });

const context = {
  week_ending: new Date().toISOString().slice(0, 10),
  pipeline: {
    new_leads_this_week: leadsW.length,
    prior_3w_avg_per_week: priorAvgPerWeek,
    trend_pct: leadsTrendPct,
    by_status: byStatus,
    by_source: bySource,
    by_industry: byIndustry
  },
  conversion: {
    bookings_this_week: bookings.length,
    bookings_by_channel: bookingsByChannel,
    quotes_sent: quotes.length,
    quotes_total_cents: totalQuotedCents,
    quotes_accepted_cents: acceptedQuotedCents,
    quotes_pending: pendingCount,
    quotes_declined: declinedCount,
    quote_acceptance_pct: acceptanceRatePct
  },
  comms: {
    outreach_volume: outreach.length,
    by_channel: outreachByChannel,
    failures: outreachFailures,
    failure_rate_pct: outreach.length > 0 ? Math.round((outreachFailures / outreach.length) * 100) : null
  },
  revenue: {
    mrr_cents: mrrCents,
    active_paying_clients: clients.filter(function (c) { return c && (c.subscription_status === 'active' || c.subscription_status === 'trialing'); }).length,
    quoted_pipeline_cents: totalQuotedCents,
    closed_this_week_cents: acceptedQuotedCents
  },
  overdue: {
    total: overdue.length,
    high_score: overdueHighScore.length,
    top_5: overdue.slice(0, 5).map(function (l) { return { company: l.company, industry: l.industry, score: l.lead_score, status: l.lead_status, days_silent: Math.floor((Date.now() - new Date(l.last_email_sent_at).getTime()) / 86400000) }; })
  }
};

const systemPrompt = [
  'You are the Crystallux COO Digital Employee. Every Monday morning Mary reads your weekly business review.',
  '',
  'Structure the review in clearly labeled sections (no markdown stars, just text headers on their own lines):',
  '',
  '## Verdict',
  'One sentence. Green / yellow / red and why.',
  '',
  '## Pipeline',
  'New leads this week vs the prior 3-week average. Where leads are coming from. What is stuck.',
  '',
  '## Conversion + revenue',
  'Bookings, quotes sent, quotes accepted, MRR, closed revenue this week. Plain numbers.',
  '',
  '## The bottleneck',
  'Pick ONE specific bottleneck (lowest-converting stage, channel with highest failure rate, industry that is silent, etc.) and name it precisely. Use the data.',
  '',
  '## Overdue work',
  'How many leads not contacted in 14+ days, especially high-score ones. Name the top 1-2 companies if any.',
  '',
  '## Recommendation',
  'ONE concrete growth experiment for this week. Specific, measurable, fits a busy founder. Not a feature request.',
  '',
  'Voice: senior COO briefing the founder. Direct. Specific numbers. No hedging. No marketing language. No em-dashes (use periods or line breaks). Maximum 350 words total.',
  '',
  'If activity is genuinely quiet (zero leads, no bookings), say so plainly. Suggest the experiment that activates pipeline rather than reporting flat numbers.'
].join('\n');

const userPrompt = 'Week ending ' + context.week_ending + '. Write the weekly business review.\n\n' + JSON.stringify(context, null, 2);

return { json: {
  review_context: context,
  payload: {
    model: 'claude-sonnet-4-6',
    max_tokens: 1400,
    system: systemPrompt,
    messages: [ { role: 'user', content: userPrompt } ]
  }
} };

// Parse Claude response, build the Postmark email + sentinel_alerts row.
const r = $input.item.json;
const ctx = $('Shape Review Context').first().json.review_context;

let review = '';
if (r && Array.isArray(r.content)) {
  const tb = r.content.find(function (b) { return b && b.type === 'text'; });
  review = tb ? tb.text : '';
}
if (!review) {
  review = 'Weekly review for ' + ctx.week_ending + '. New leads this week: ' + ctx.pipeline.new_leads_this_week + '. Bookings: ' + ctx.conversion.bookings_this_week + '. Quotes sent: ' + ctx.conversion.quotes_sent + '. Overdue leads: ' + ctx.overdue.total + '. Claude did not respond cleanly so this is a fallback.';
}

// Format MRR as money
function fmtMoney(cents) {
  if (cents == null) return '$0';
  return '$' + (cents / 100).toLocaleString('en-CA', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
}

// Render review with section headers styled (turn lines starting with ## into bold)
const reviewHtml = review.split('\n').map(function (line) {
  if (line.startsWith('## ')) {
    return '<div style="font-size:13px;font-weight:700;color:#0f4c81;text-transform:uppercase;letter-spacing:0.05em;margin-top:18px;margin-bottom:6px;">' + line.slice(3) + '</div>';
  }
  if (line.trim() === '') return '<div style="height:8px"></div>';
  return '<div style="font-size:14px;line-height:1.6;color:#0f172a;margin-bottom:4px;">' + line.replace(/</g, '&lt;') + '</div>';
}).join('');

const htmlBody = '<div style="font-family:Arial,Helvetica,sans-serif;color:#0f172a;max-width:680px;">' +
  '<div style="padding:24px 28px;background:linear-gradient(135deg,#7C3AED 0%,#5B21B6 100%);color:#fff;border-radius:8px 8px 0 0;">' +
    '<div style="font-size:12px;font-weight:700;letter-spacing:0.08em;text-transform:uppercase;opacity:0.85;">Crystallux COO</div>' +
    '<div style="font-size:24px;font-weight:800;margin-top:6px;letter-spacing:-0.01em;">Weekly review &middot; ' + ctx.week_ending + '</div>' +
  '</div>' +
  '<div style="padding:28px;background:#fff;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 8px 8px;">' +
    reviewHtml +
    '<table style="width:100%;border-collapse:collapse;font-size:13px;margin-top:24px;border-top:1px solid #e5e7eb;padding-top:16px;">' +
      '<tr><td style="padding:6px 0;color:#64748b;">New leads this week</td><td style="padding:6px 0;text-align:right;font-weight:700;">' + ctx.pipeline.new_leads_this_week + (ctx.pipeline.trend_pct != null ? ' <span style="font-size:11px;color:' + (ctx.pipeline.trend_pct >= 0 ? '#16a34a' : '#dc2626') + ';">(' + (ctx.pipeline.trend_pct >= 0 ? '+' : '') + ctx.pipeline.trend_pct + '%)</span>' : '') + '</td></tr>' +
      '<tr><td style="padding:6px 0;color:#64748b;">Bookings this week</td><td style="padding:6px 0;text-align:right;font-weight:700;">' + ctx.conversion.bookings_this_week + '</td></tr>' +
      '<tr><td style="padding:6px 0;color:#64748b;">Quotes sent</td><td style="padding:6px 0;text-align:right;font-weight:700;">' + ctx.conversion.quotes_sent + (ctx.conversion.quote_acceptance_pct != null ? ' &middot; ' + ctx.conversion.quote_acceptance_pct + '% accept' : '') + '</td></tr>' +
      '<tr><td style="padding:6px 0;color:#64748b;">MRR (paying clients)</td><td style="padding:6px 0;text-align:right;font-weight:700;">' + fmtMoney(ctx.revenue.mrr_cents) + '</td></tr>' +
      '<tr><td style="padding:6px 0;color:#64748b;">Closed revenue (this week)</td><td style="padding:6px 0;text-align:right;font-weight:700;">' + fmtMoney(ctx.revenue.closed_this_week_cents) + '</td></tr>' +
      '<tr><td style="padding:6px 0;color:#64748b;">Overdue leads (14d+)</td><td style="padding:6px 0;text-align:right;font-weight:700;color:' + (ctx.overdue.high_score > 0 ? '#dc2626' : '#0f172a') + ';">' + ctx.overdue.total + (ctx.overdue.high_score > 0 ? ' &middot; ' + ctx.overdue.high_score + ' high-score' : '') + '</td></tr>' +
      '<tr><td style="padding:6px 0;color:#64748b;">Comms volume</td><td style="padding:6px 0;text-align:right;font-weight:700;">' + ctx.comms.outreach_volume + (ctx.comms.failure_rate_pct ? ' &middot; ' + ctx.comms.failure_rate_pct + '% fail rate' : '') + '</td></tr>' +
    '</table>' +
    '<div style="margin-top:24px;font-size:11px;color:#94a3b8;">Open the admin dashboard for drill-down: <a href="https://admin.crystallux.org/pages/sales-engine.html" style="color:#7C3AED;">admin.crystallux.org/pages/sales-engine</a></div>' +
  '</div>' +
  '</div>';

const maryEmail = $env.MARY_EMAIL || 'adesholaakintunde@gmail.com';
const fromAddr  = $env.POSTMARK_FROM || 'mary@crystallux.org';

return { json: {
  review_text: review,
  review_context: ctx,
  postmark_payload: {
    From: fromAddr,
    To: maryEmail,
    Subject: 'Weekly review &middot; ' + ctx.week_ending + ' &middot; ' + ctx.pipeline.new_leads_this_week + ' new leads, ' + ctx.conversion.bookings_this_week + ' bookings',
    HtmlBody: htmlBody,
    TextBody: review,
    MessageStream: 'outbound'
  },
  sentinel_alert_row: {
    module_name: 'coo',
    alert_type: 'weekly_review',
    severity: ctx.overdue.high_score > 5 ? 'warning' : 'info',
    title: 'COO weekly review — ' + ctx.week_ending,
    message: review.slice(0, 2000),
    details: { review_context: ctx },
    status: 'resolved',
    aggregation_key: 'coo:weekly:' + ctx.week_ending
  }
} };
